import React, { useState } from "react";
import { api } from "../../api";

const LoginPage = ({ onSuccess, onNavigate }) => {
  // 1. Объявляем состояния (стейты)
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  // 2. Объявляем функцию обработки формы
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const data = await api.login({ email, password });
      if (data.accessToken) {
        // Вызываем onSuccess, который пришел из App.js
        onSuccess(data.accessToken, data.user);
      }
    } catch (err) {
      alert("Ошибка: " + (err.response?.data?.error || "Неверный логин или пароль"));
    }
  };

  // 3. Возвращаем визуальную часть
  return (
    <div className="login-container">
      <form className="login-form" onSubmit={handleSubmit}>
        <h2>Вход в аккаунт</h2>
        
        <div className="form-group">
          <input
            type="email"
            placeholder="Ваш email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
        </div>

        <div className="form-group">
          <input
            type="password"
            placeholder="Ваш пароль"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />
        </div>

        <button type="submit" className="login-button">
          Войти
        </button>
      </form>

      <div className="login-footer">
        <span>Нет аккаунта? </span>
        <button className="link-button" onClick={onNavigate}>
          Зарегистрироваться
        </button>
      </div>
    </div>
  );
};

// 4. Экспорт только ОДИН раз в самом конце
export default LoginPage;
